//! Tier 6 backing: Embedding service — vector generation, cosine similarity, and in-memory vector index.
//!
//! Provides a local vector store that persists to JSON. The actual embedding
//! vectors are generated by the provider's `embed()` method; this module handles
//! storage, indexing, and similarity search.

use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use std::path::{Path, PathBuf};

/// A stored embedding with its source text and metadata.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StoredEmbedding {
    pub id: String,
    pub source_text: String,
    pub source_type: String, // "lesson", "timeline", "procedure", "user_note"
    pub vector: Vec<f32>,
    pub created_at: chrono::DateTime<chrono::Utc>,
}

/// In-memory vector index backed by a JSON file.
pub struct EmbeddingStore {
    embeddings: Vec<StoredEmbedding>,
    file_path: Option<PathBuf>,
    dimensions: usize,
}

impl EmbeddingStore {
    /// Create an in-memory-only store.
    pub fn new() -> Self {
        Self {
            embeddings: Vec::new(),
            file_path: None,
            dimensions: 0,
        }
    }

    /// Create a store backed by a JSON file. Loads existing vectors if the file exists.
    pub fn open(path: &Path) -> Result<Self> {
        let mut store = Self {
            embeddings: Vec::new(),
            file_path: Some(path.to_path_buf()),
            dimensions: 0,
        };

        if path.exists() {
            let content = std::fs::read_to_string(path)
                .with_context(|| format!("Failed to read embeddings file: {}", path.display()))?;
            store.embeddings = serde_json::from_str(&content)
                .with_context(|| format!("Failed to parse embeddings file: {}", path.display()))?;

            // Derive dimensions from first entry
            if let Some(first) = store.embeddings.first() {
                store.dimensions = first.vector.len();
            }

            tracing::info!(
                count = store.embeddings.len(),
                dims = store.dimensions,
                "Loaded embedding store from disk"
            );
        }

        Ok(store)
    }

    fn persist(&self) -> Result<()> {
        if let Some(ref path) = self.file_path {
            if let Some(parent) = path.parent() {
                std::fs::create_dir_all(parent).with_context(|| {
                    format!("Failed to create embeddings dir: {}", parent.display())
                })?;
            }
            let content = serde_json::to_string(&self.embeddings)
                .context("Failed to serialize embeddings")?;
            std::fs::write(path, content)
                .with_context(|| format!("Failed to write embeddings file: {}", path.display()))?;
        }
        Ok(())
    }

    /// Insert a new embedding. Caller is responsible for generating the vector via provider.embed().
    pub fn insert(
        &mut self,
        source_text: &str,
        source_type: &str,
        vector: Vec<f32>,
    ) -> Result<String> {
        if self.dimensions == 0 && !vector.is_empty() {
            self.dimensions = vector.len();
        }

        let id = uuid::Uuid::new_v4().to_string();
        self.embeddings.push(StoredEmbedding {
            id: id.clone(),
            source_text: source_text.to_string(),
            source_type: source_type.to_string(),
            vector,
            created_at: chrono::Utc::now(),
        });

        self.persist()?;
        Ok(id)
    }

    /// Find the top-K most similar embeddings to the given query vector.
    /// Returns (embedding, similarity_score) pairs sorted by descending similarity.
    pub fn search(&self, query_vector: &[f32], top_k: usize) -> Vec<(&StoredEmbedding, f32)> {
        let mut scored: Vec<(&StoredEmbedding, f32)> = self
            .embeddings
            .iter()
            .map(|emb| {
                let sim = cosine_similarity(query_vector, &emb.vector);
                (emb, sim)
            })
            .collect();

        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
        scored.truncate(top_k);
        scored
    }

    /// Remove an embedding by ID.
    pub fn remove(&mut self, id: &str) -> Result<()> {
        let before = self.embeddings.len();
        self.embeddings.retain(|e| e.id != id);
        if self.embeddings.len() == before {
            anyhow::bail!("Embedding '{}' not found", id);
        }
        self.persist()?;
        Ok(())
    }

    pub fn dimensions(&self) -> usize {
        self.dimensions
    }
    pub fn count(&self) -> usize {
        self.embeddings.len()
    }
}

/// Compute cosine similarity between two vectors.
pub fn cosine_similarity(a: &[f32], b: &[f32]) -> f32 {
    if a.len() != b.len() || a.is_empty() {
        return 0.0;
    }
    let dot: f32 = a.iter().zip(b).map(|(x, y)| x * y).sum();
    let norm_a: f32 = a.iter().map(|x| x * x).sum::<f32>().sqrt();
    let norm_b: f32 = b.iter().map(|x| x * x).sum::<f32>().sqrt();
    if norm_a == 0.0 || norm_b == 0.0 {
        return 0.0;
    }
    dot / (norm_a * norm_b)
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn test_cosine_identical() {
        let a = vec![1.0, 0.0, 0.0];
        let similarity = cosine_similarity(&a, &a);
        assert!((similarity - 1.0).abs() < f32::EPSILON);
    }

    #[test]
    fn test_cosine_orthogonal() {
        let a = vec![1.0, 0.0];
        let b = vec![0.0, 1.0];
        assert!(cosine_similarity(&a, &b).abs() < f32::EPSILON);
    }

    #[test]
    fn test_cosine_opposite() {
        let a = vec![1.0, 0.0];
        let b = vec![-1.0, 0.0];
        assert!((cosine_similarity(&a, &b) + 1.0).abs() < f32::EPSILON);
    }

    #[test]
    fn test_cosine_different_lengths() {
        let a = vec![1.0, 0.0];
        let b = vec![1.0, 0.0, 0.0];
        assert_eq!(cosine_similarity(&a, &b), 0.0);
    }

    #[test]
    fn test_insert_and_search() {
        let mut store = EmbeddingStore::new();
        store
            .insert("Rust is fast", "test", vec![1.0, 0.0, 0.0])
            .unwrap();
        store
            .insert("Python is slow", "test", vec![0.0, 1.0, 0.0])
            .unwrap();
        store
            .insert("Rust is memory safe", "test", vec![0.9, 0.1, 0.0])
            .unwrap();

        let query = vec![1.0, 0.0, 0.0];
        let results = store.search(&query, 2);
        assert_eq!(results.len(), 2);
        assert_eq!(results[0].0.source_text, "Rust is fast");
        assert!(results[0].1 > results[1].1);
    }

    #[test]
    fn test_persist_and_reload() {
        let tmp = TempDir::new().unwrap();
        let path = tmp.path().join("embeddings.json");

        {
            let mut store = EmbeddingStore::open(&path).unwrap();
            store.insert("Hello", "test", vec![1.0, 0.5]).unwrap();
            store.insert("World", "test", vec![0.5, 1.0]).unwrap();
        }

        {
            let store = EmbeddingStore::open(&path).unwrap();
            assert_eq!(store.count(), 2);
            assert_eq!(store.dimensions(), 2);
        }
    }

    #[test]
    fn test_remove() {
        let mut store = EmbeddingStore::new();
        let id = store.insert("test", "test", vec![1.0]).unwrap();
        store.remove(&id).unwrap();
        assert_eq!(store.count(), 0);
    }
}
